class Solution:
    def minimumOperations(self, nums: List[int], target: List[int]) -> int:
        operations = 0
        running_diff = 0

        for i in range(len(nums)):
            running_diff += nums[i] - target[i]
            if running_diff < 0:
                operations -= running_diff
                running_diff = 0
            elif running_diff > 0:
                operations += running_diff
                running_diff = 0

        return operations
